// Tomamos el body real del webhook
const data = $json.body || {};

let channel = null;
let platform_user_id = null;
let message = null;

// Caso Telegram (simulado simple)
if (data.message) {
  channel = "telegram";
  platform_user_id = data.message.from?.id?.toString();
  message = data.message.text;
}

// Caso WhatsApp (Meta Cloud API estructura real)
else if (data.entry) {
  channel = "whatsapp";
  platform_user_id = data.entry[0].changes[0].value.messages[0].from;
  message = data.entry[0].changes[0].value.messages[0].text?.body;
}

// Caso Email simple
else if (data.from && data.subject) {
  channel = "email";
  platform_user_id = data.from;
  message = data.text || data.body;
}

// Fallback
else {
  channel = "unknown";
  platform_user_id = "unknown";
  message = JSON.stringify(data);
}

return [{
  channel,
  platform_user_id,
  message
}];

const message = $node["Universal normalization"].json.message;

// Robust Regex to detect emails
const emailMatch = message
  ? message.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i)
  : null;

return [{
  ...$json,
  extracted_email: emailMatch ? emailMatch[0].toLowerCase() : null
}];

const otp = Math.floor(100000 + Math.random() * 900000).toString();

return [{
  ...$json,
  otp_code: otp,
  otp_expires_at: new Date(Date.now() + 5 * 60 * 1000) // 5 minutos
}];

